const axios = require('axios');
const cheerio = require('cheerio');
const url = require('url');

const ALLOWED_DOMAINS = ['example.com', 'another-example.com']; // Add your allowed domains here

const isValidDomain = (inputUrl) => {
    const parsedUrl = new URL(inputUrl);
    return ALLOWED_DOMAINS.includes(parsedUrl.hostname);
};

const fetchMetadata = async (inputUrl) => {
    if (!isValidDomain(inputUrl)) {
        throw new Error('Invalid URL: Domain not allowed');
    }

    try {
        const response = await axios.get(inputUrl, {
            validateStatus: (status) => status >= 200 && status < 400,
        });

        const $ = cheerio.load(response.data);
        const title = $('meta[property="og:title"]').attr('content') || $('title').text();
        const description = $('meta[property="og:description"]').attr('content') || $('meta[name="description"]').attr('content');

        return {
            title,
            description,
        };
    } catch (error) {
        throw new Error('Failed to fetch metadata: ' + error.message);
    }
};

module.exports = { fetchMetadata };